import * as React from "react"
import Header from "./header"
import Footer from "./footer"
import { useStaticQuery, graphql, Link } from "gatsby"

const Layout = ({ children }) => {
 const dataNav = useStaticQuery(graphql`
  query {
   allSitePage {
    nodes {
     path
     component
    }
   }
  }
 `)

 const pages = dataNav.allSitePage.nodes.filter(page => {
  return !page.path.includes("404") && !page.path.includes("using")
 })

 return (
  &lt;>
   &lt;Header />
   &lt;nav>
    {pages.map(page => (
     &lt;span>
      &lt;Link to={page.path}>
       {page.path.replaceAll("/", "").replaceAll("_", " ") || "Home"}
      &lt;/Link> {" | "}
     &lt;/span>
    ))}
   &lt;/nav>
   &lt;main>{children}&lt;/main>
  &lt;Footer />
 &lt;/>
)
}

export default Layout
